import type { UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import { UmbSubmittableWorkspaceContextBase, UmbWorkspaceIsNewRedirectController } from "@umbraco-cms/backoffice/workspace";
import type { UmbControllerHostElement } from "@umbraco-cms/backoffice/controller-api";
import { UmbObjectState } from "@umbraco-cms/backoffice/observable-api";
import type { FormDataSource } from "@umbraco-forms/generated";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { UmbRequestReloadChildrenOfEntityEvent, UmbRequestReloadStructureForEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { FORMS_DATASOURCE_ENTITY_TYPE, FORMS_DATASOURCE_ROOT_ENTITY_TYPE } from "../entities.js";
import { FormsDataSourceDetailRepository } from "../repository/index.js";
import { FormsDataSourceTypeDetailRepository } from "../../provider-types/datasource-types/repository/detail/index.js";
import { DATASOURCE_WORKSPACE_ALIAS } from "./manifests.js";
import FormsWorkspaceEditorElement from "./datasource-workspace-editor.element.js";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { UmbLocalizationController } from "@umbraco-cms/backoffice/localization-api";

export class FormsDataSourceWorkspaceContext
  extends UmbSubmittableWorkspaceContextBase<FormDataSource>
  implements UmbSubmittableWorkspaceContext
{
  public readonly dataSourceRepository = new FormsDataSourceDetailRepository(this);
  public readonly dataSourceTypeRepository = new FormsDataSourceTypeDetailRepository(this);

  #data = new UmbObjectState<FormDataSource | undefined>(undefined);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  #getDataPromise?: Promise<any>;

  readonly data = this.#data.asObservable();
  readonly unique = this.#data.asObservablePart((data) => data?.unique);
  readonly name = this.#data.asObservablePart((data) => data?.name);
  readonly id = this.#data.asObservablePart((data) => data?.unique);

  constructor(host: UmbControllerHostElement) {
    super(host, DATASOURCE_WORKSPACE_ALIAS);

    this.routes.setRoutes([
      {
        path: "create/:type",
        component: FormsWorkspaceEditorElement,
        setup: async (_component, info) => {
          const dataSourceType = info.match.params.type;
          await this.create(dataSourceType);
        },
      },
      {
        path: "edit/:unique",
        component: FormsWorkspaceEditorElement,
        setup: (_component, info) => {
          const unique = info.match.params.unique;
          this.load(unique);
        },
      },
    ]);
  }

  async load(id: string) {
    this.#getDataPromise = this.dataSourceRepository.requestByUnique(id);
    const { data } = await this.#getDataPromise;

    if (data) {
      this.setIsNew(false);
      this.#data.update(data);
    }
  }

  async create(type: string) {
    const scaffold = await this.dataSourceRepository.requestDataSourceScaffold();

    let data = scaffold.data!;
    data.formDataSourceTypeId = type;

    if (this.modalContext) {
      data = { ...data, ...this.modalContext.data.preset };
    }
    this.setIsNew(true);
    this.#data.setValue(data);
    return { data };
  }

  async submit(): Promise<void> {
    if (!this.#data.value) return;
    if (!this.#data.value.unique) return;

    if (this.#data.value.name.trim().length === 0) {
      const notificationContext = await this.getContext(
        UMB_NOTIFICATION_CONTEXT
      );
      const localize = new UmbLocalizationController(this);
      notificationContext.peek("danger", {
        data: { message: localize.term("formEdit_noNameForForm") },
      });
      return;
    }

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);

    if (this.getIsNew()) {
      await this.dataSourceRepository.create(this.#data.value, null);

			const event = new UmbRequestReloadChildrenOfEntityEvent ({
				entityType: FORMS_DATASOURCE_ROOT_ENTITY_TYPE,
				unique: null,
			});
			eventContext.dispatchEvent(event);
      this.setIsNew(false);
    } else {
      await this.dataSourceRepository.save(this.#data.value);

      const event = new UmbRequestReloadStructureForEntityEvent({
        unique: this.getUnique()!,
        entityType: this.getEntityType(),
      });
      eventContext.dispatchEvent(event);
    }
  }

  async loadDataSourceType(id: string) {
    const { data } = await this.dataSourceTypeRepository.requestByUnique(id);
    return data;
  }

  getData() {
    return this.#data.getValue();
  }

  getUnique() {
		return this.getData()?.unique || '';
	}

  getDataSourceTypeId() {
		return this.getData()?.formDataSourceTypeId || '';
	}

  getEntityType(): string {
    return FORMS_DATASOURCE_ENTITY_TYPE;
  }

  getName() {
    return this.#data.getValue()?.name;
  }

  setName(name: string) {
    this.#data.update({ name });
  }

  setDataSourceProperty(alias: string, value: any) {
    this.#data.update({ [alias]: value });
  }

  getDataSourceProperty(alias: string) {
    return this.getData()?.[alias];
  }

  async getWizardScaffold() {
    const { data } = await this.dataSourceRepository.requestDataSourceWizardScaffold(this.getUnique());
    return data;
  }

  destroy() {
    this.#data.destroy();
  }
}

export const api = FormsDataSourceWorkspaceContext;
