import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import {
  LitElement,
  css,
  customElement,
  html,
  property,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import {
  UUIInputEvent
} from "@umbraco-cms/backoffice/external/uui";
import { FORMS_DATASOURCE_WORKSPACE_CONTEXT } from "./datasource-workspace.context-token.js";

const elementName = "forms-datasource-workspace-editor";

@customElement(elementName)
export class FormsDataSourceWorkspaceEditorElement extends UmbElementMixin(LitElement) {
  @state()
  private _dataSourceName = "";

	@property({ type: String, attribute: false })
	workspaceAlias?: string;

  #workspaceContext?: typeof FORMS_DATASOURCE_WORKSPACE_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(FORMS_DATASOURCE_WORKSPACE_CONTEXT, (context) => {
      this.#workspaceContext = context;
			this.#observeId();
		});
	}

	#observeId() {
		if (!this.#workspaceContext) return;
		this.observe(this.#workspaceContext.data, (data) => (this._dataSourceName = data?.name ?? ''));
	}

  #onChangeName(e: UUIInputEvent) {
    this.#workspaceContext?.setName(e.target.value.toString());
  }

  render() {
    return html` <umb-workspace-editor alias="Forms.Workspace.DataSources">
      <uui-input
        slot="header"
        id="nameInput"
        label=${this.localize.term('placeholders_entername')}
        placeholder=${this.localize.term('placeholders_entername')}
        required
        .value=${this._dataSourceName}
        @input="${this.#onChangeName}"
      ></uui-input>
    </umb-workspace-editor>`;
  }

  static styles = [
    css`
        :host {
            display: block;
            width: 100%;
            height: 100%;
        }

        #nameInput {
            flex: 1 1 auto;
        }
    `,
];}

export default FormsDataSourceWorkspaceEditorElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsDataSourceWorkspaceEditorElement;
  }
}
